94	export interface ClaimResult {
95	  payout: number;
96	  remainingCap: number;
97	}
98	
99	const DEDUCTIBLE = 100;
100	
101	export function claim(input: ClaimInput): ClaimResult {
102	  const damage = input.incident.damages[0];
103	  const payout = damage.amount - DEDUCTIBLE;
104	  // remainingCap is not yet exercised by any test; its behaviour is driven by
105	  // the "claim — cap" tests still to come.
106	  return { payout, remainingCap: undefined as unknown as number };
107	}
